#include <stdio.h>
#include <unistd.h>
#include <sys/types.h>

int main() {
    pid_t pid;

    printf("Before fork - Parent Process ID: %d\n", getpid());

    pid = fork();  // System call to create new process

    if (pid < 0) {
        // Error occurred
        printf("Fork failed!\n");
        return 1;
    }
    else if (pid == 0) {
        // Child process
        printf("Child Process - My PID: %d, Parent PID: %d\n", 
               getpid(), getppid());
    }
    else {
        // Parent process
        printf("Parent Process - My PID: %d, Child PID: %d\n", 
               getpid(), pid);
        wait(NULL);  // Wait for child to complete
        printf("Child process completed\n");
    }

    return 0;
}

#include <stdio.h>
#include <fcntl.h>
#include <unistd.h>

int main() {
    int fd;
    char buffer[100];
    ssize_t bytes_read, bytes_written;

    // Create and open file using open() system call
    // O_CREAT: create if doesn't exist, O_WRONLY: write only, O_TRUNC: truncate
    fd = open("test.txt", O_CREAT | O_WRONLY | O_TRUNC, 0644);

    if (fd < 0) {
        perror("Error opening file");
        return 1;
    }

    // Write to file using write() system call
    char *msg = "Hello, this is a system call demo!\n";
    bytes_written = write(fd, msg, 34);
    printf("Written %zd bytes to file\n", bytes_written);

    // Close file using close() system call
    close(fd);

    // Reopen for reading
    fd = open("test.txt", O_RDONLY);
    if (fd < 0) {
        perror("Error opening file");
        return 1;
    }

    // Read from file using read() system call
    bytes_read = read(fd, buffer, 100);
    printf("Read %zd bytes: %s\n", bytes_read, buffer);

    close(fd);
    return 0;
}

#include <stdio.h>
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>

int main() {
    pid_t pid;

    pid = fork();

    if (pid < 0) {
        printf("Fork failed\n");
        return 1;
    }
    else if (pid == 0) {
        // Child process - execute 'ls' command
        // execlp() searches in PATH for 'ls'
        // Arguments: program name, arg0, arg1, ..., NULL
        execlp("ls", "ls", "-l", "-a", NULL);

        // If execlp returns, an error occurred
        perror("execlp failed");
        _exit(1);
    }
    else {
        // Parent waits for child
        wait(NULL);
        printf("Child process completed execution\n");
    }

    return 0;
}
